% Plot ESKF C++ Results (cpp_results.csv)
% This script reads the CSV generated by the C++ test harness and
% uses the existing plot_eskf_results function to visualize them.

% Clear workspace
clear; clc; close all;

% Check if file exists
csv_file = 'cpp_results.csv';
if ~isfile(csv_file)
    error('File %s not found. Please run the C++ test harness first.', csv_file);
end

% Read CSV data
fprintf('Reading %s...\n', csv_file);
% Skip header row (1)
data = readmatrix(csv_file, 'NumHeaderLines', 1);

% Extract time
t = data(:, 1)';
N = length(t);

% === Construct Estimated State Matrix (18 x N) ===
% CSV Columns for Est:
% 2-4: pos (x,y,z) -> pr
% 5-7: vel (x,y,z) -> vr
% 8-11: q (w,x,y,z) -> q
% 12-13: pbar (x,y) -> pbar
% 14-16: bg (x,y,z) -> bgyr
% 17-19: ba (x,y,z) -> bacc

% Define target row indices (1-based, matching EskfTypes)
idx_q = 1:4;
idx_pr = 5:7;
idx_vr = 8:10;
idx_pbar = 11:12;
idx_bgyr = 13:15;
idx_bacc = 16:18;

x_est = zeros(18, N);
x_est(idx_q, :) = data(:, 8:11)';      % q
x_est(idx_pr, :) = data(:, 2:4)';      % pr
x_est(idx_vr, :) = data(:, 5:7)';      % vr
x_est(idx_pbar, :) = data(:, 12:13)';  % pbar
x_est(idx_bgyr, :) = data(:, 14:16)';  % bgyr
x_est(idx_bacc, :) = data(:, 17:19)';  % bacc

% === Construct True State Matrix (18 x N) ===
% CSV Columns for True:
% 20-22: pos -> pr
% 23-25: vel -> vr
% 26-29: q -> q
% 30-31: pbar -> pbar
% 32-34: bg -> bgyr
% 35-37: ba -> bacc

x_true = zeros(18, N);
x_true(idx_q, :) = data(:, 26:29)';    % q
x_true(idx_pr, :) = data(:, 20:22)';   % pr
x_true(idx_vr, :) = data(:, 23:25)';   % vr
x_true(idx_pbar, :) = data(:, 30:31)'; % pbar
x_true(idx_bgyr, :) = data(:, 32:34)'; % bgyr
x_true(idx_bacc, :) = data(:, 35:37)'; % bacc

% === Construct Covariance Diagonal (17 x N) ===
% CSV Columns: 38-54
P_diag = data(:, 38:54)';

% Define error state indices
idx_dtheta = 1:3;
idx_dpr = 4:6;
idx_dvr = 7:9;
idx_dpbar = 10:11;
idx_dbgyr = 12:14;
idx_dbacc = 15:17;

% === Call Plot Function ===
fprintf('Generating plots...\n');
plot_eskf_results(t, x_true, x_est, P_diag, ...
                  idx_q, idx_pr, idx_vr, idx_pbar, idx_bgyr, idx_bacc, ...
                  idx_dtheta, idx_dpr, idx_dvr, idx_dpbar, idx_dbgyr, idx_dbacc);

fprintf('Done!\n');
